<script setup>
//  watch, onBeforeUnmount, computed
import { ref, computed } from "vue";
import { useDebitsStore } from "@/stores/debits";
import PopRetrieveItems from "@/components/sales/PopRetrieveItems.vue";
import InvoiceReceipt from "@/components/layout/invoice.vue";
import { h, render, nextTick } from "vue";
import moment from "moment-timezone";
import { useSnackbarStore } from "@/stores/snackbar";

const emit = defineEmits(["itemUpdated", "popClose"]);
const debitsStore = useDebitsStore();

defineProps({
  dialog: { type: Boolean, default: false },
});

const info_user = computed(() => debitsStore.statistics_debtor_user.debtorUser);
const sales_debtor = computed(() => debitsStore.info_all_sale);
const loading = computed(() => debitsStore.loading_add_payment);
const loading_debit = computed(() => debitsStore.loading_change_debit_type);

const tabs = ref(0);
const payment = ref(0);
const payment_value = ref(null);

const sale_item_id = ref(null);
const quantity = ref(null);
const max_quantity_retrieve = ref(1);
const dialog_retrieve_items = ref(false);

function changeTabs(tab) {
 tabs.value = tab;
}

function popRetrieveItems(item) {
  sale_item_id.value = item.id;
  max_quantity_retrieve.value = item.quantity;
  dialog_retrieve_items.value = true;
}

function retrieveQuantity(retrieve_quantity) {
  quantity.value = retrieve_quantity;
  retrieve();
}

const retrieve = async () => {
  let data = {
    sale_item_id: sale_item_id.value,
    sale_id: sales_debtor?.value.id,
    debtor_user_id: sales_debtor?.value.payment_dates.debtor_user_id,
    payment_date_id: sales_debtor?.value.payment_dates.id,
    quantity: quantity.value,
  };

  try {
    const response = await debitsStore.retrieve_item_debtor(data);
    emit("itemUpdated", response.data.result[0]);
  } catch (e) {
    console.error("Error in store", e);
  }
};

function addPayment(val) {
  payment.value = val;
}

async function add_payment(payment) {
  let data = {};
  data["payment_date_id"] = payment.id;
  data["debtor_user_id"] = payment.debtor_user_id;
  data["amount_paid"] = payment_value.value;

  try {
    await debitsStore.add_new_payment(data);
    addPayment(0);
    payment_value.value = null;
  } catch (e) {
    console.error("Error in store", e);
  }
}

async function changeDebitType(sale) {
  let data = {};
  data["sale_id"] = sale.id;
  data["debtor_user_id"] = sale.debtor_user_id;
  data["payment_date_id"] = sale.payment_dates.id;

  await debitsStore.change_debit_type(data);

  await debitsStore.get_statistics_debtor_user();

  debitsStore.sales_debtor = [];
  debitsStore.params_debtor.page = 1;
  debitsStore.debtor_state = "done";
  await debitsStore.get_sales_to_debtor();

  const snackbar = useSnackbarStore();
  snackbar.showMessage({
    color: "deep-purple-accent-4",
    icon: "clarity:success-standard-solid",
    text: "تم تغيير حالة البيع للفاتورة بنجاح",
  });

  emit("popClose");
  debitsStore.loading_change_debit_type = false;
}

const displayPrice = computed(() => {
  if (!payment_value.value) return "";
  return new Intl.NumberFormat("en-US").format(Number(payment_value.value));
});

const onInput = (val) => {
  const str = (val ?? "").toString();
  let onlyNumbers = str.replace(/\D/g, ""); // إزالة أي شيء غير رقم
  let numericValue = Number(onlyNumbers);

  // لا تسمح بكتابة أكثر من المبلغ المستحق
  if (
    numericValue > Number(sales_debtor.value?.payment_dates.remaining_amount)
  ) {
    // ترجع للقيمة السابقة بدل السماح بالتجاوز
    numericValue = Number(sales_debtor.value?.payment_dates.remaining_amount);
  }

  payment_value.value = numericValue ? numericValue.toString() : "";
};

// منع أي حرف غير رقم أثناء الكتابة
const allowOnlyNumbers = (event) => {
  const key = event.key;

  // السماح فقط بالأرقام
  if (!/^[0-9]$/.test(key)) {
    event.preventDefault();
    return;
  }

  // التحقق من القيمة الحالية + المفتاح الجديد
  const currentValue = payment_value.value + key;
  const numericValue = Number(currentValue);

  // منع الكتابة إذا تجاوز الحد قبل حتى إدخاله
  if (
    numericValue > Number(sales_debtor.value?.payment_dates.remaining_amount)
  ) {
    event.preventDefault();
  }
};

function payments_value(val) {
  if (val == "all") {
    payment_value.value = sales_debtor.value?.payment_dates.remaining_amount;
  } else {
    payment_value.value =
      sales_debtor.value?.payment_dates.remaining_amount / 2;
  }
}

function cardStyle(variant) {
  if (variant === "paid") return "card-paid";
  if (variant === "partially_paid") return "card-partially-paid";
  if (variant === "unpaid") return "card-unpaid";
  return "";
}

// طباعة فاتورة
const paperSize = ref("size-80");
const nameStore = ref("علاء حداد فرع الديوانية");

let isPrinting = false;

function printInvoice(items) {
  if (isPrinting) return;
  isPrinting = true;

  // حاوية الطباعة المباشرة تحت body
  const container = document.createElement("div");
  container.id = "print-root"; // مهم جداً للـ CSS أدناه
  container.style.position = "fixed";
  container.style.left = "0";
  container.style.top = "0";
  container.style.zIndex = "2147483647";
  document.body.appendChild(container);

  const cleanup = () => {
    render(null, container);
    container.remove();
    window.removeEventListener("afterprint", cleanup);
    isPrinting = false;
  };

  const vnode = h(InvoiceReceipt, {
    purchasedItems: items.sale_items,
    nameStore: nameStore.value,
    paperSize: paperSize.value,
    saleType: items.sale_type,
    invoiceId: items.invoice_number,
    date: items.created_at,

    name: info_user.value.name,
    phone: info_user.value.phone,
    city: info_user.value.city,

    total: items.total,
    amount_paid: items.payment_dates.amount_paid,
    remaining_amount: items.payment_dates.remaining_amount,
    onReady: async () => {
      await nextTick();
      requestAnimationFrame(() => {
        window.addEventListener("afterprint", cleanup, { once: true });
        window.print(); // نسخة واحدة فقط
      });
    },
  });

  render(vnode, container);
}

const isExpired = (item) => {
  // استثناء الطلبات الآجلة
  if (item.sale_type === 1) return false;

  const now = moment().tz("Asia/Baghdad");
  const createdAt = moment(item.created_at).tz("Asia/Baghdad");

  // تحقق من أن تاريخ الطلب هو اليوم فقط
  const isSameDay = now.isSame(createdAt, "day");

  // إذا ليس نفس اليوم، نعتبره منتهي مباشرة
  if (!isSameDay) return true;

  // تحقق من فرق الوقت (بالساعات)
  return now.diff(createdAt, "hours", true) >= 1;
};
